  1→import { Bot } from 'grammy'
  2→import { ChannelAdapter, type OpenACPCore, type OutgoingMessage, type PermissionRequest, type NotificationMessage, type Session, log } from '@openacp/core'
  3→import type { TelegramChannelConfig } from './types.js'
  4→import { MessageDraft } from './streaming.js'
  5→import { ensureTopics, createSessionTopic, renameSessionTopic } from './topics.js'
  6→import { setupCommands } from './commands.js'
  7→import { PermissionHandler } from './permissions.js'
  8→import { spawnAssistant, handleAssistantMessage, redirectToAssistant } from './assistant.js'
  9→import { escapeHtml, formatToolCall, formatToolUpdate, formatPlan, formatUsage } from './formatting.js'
 10→
 11→export class TelegramAdapter extends ChannelAdapter {
 12→  private bot!: Bot
 13→  private telegramConfig: TelegramChannelConfig
 14→  private sessionDrafts: Map<string, MessageDraft> = new Map()
 15→  private toolCallMessages: Map<string, Map<string, number>> = new Map()  // sessionId → (toolCallId → msgId)
 16→  private permissionHandler!: PermissionHandler
 17→  private assistantSession: Session | null = null
 18→  private notificationTopicId!: number
 19→  private assistantTopicId!: number
 20→
 21→  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
 22→    super(core, config as any)
 23→    this.telegramConfig = config
 24→  }
 25→
 26→  async start(): Promise<void> {
 27→    this.bot = new Bot(this.telegramConfig.botToken)
 28→
 29→    // Middleware: only accept messages from configured chatId
 30→    this.bot.use((ctx, next) => {
 31→      if (ctx.chat?.id !== this.telegramConfig.chatId) return
 32→      return next()
 33→    })
 34→
 35→    // Ensure system topics exist
 36→    const topics = await ensureTopics(
 37→      this.bot,
 38→      this.telegramConfig.chatId,
 39→      this.telegramConfig,
 40→      async (updates) => {
 41→        // Save topic IDs to config
 42→        await (this.core as OpenACPCore).configManager.save({
 43→          channels: { telegram: updates }
 44→        })
 45→      }
 46→    )
 47→    this.notificationTopicId = topics.notificationTopicId
 48→    this.assistantTopicId = topics.assistantTopicId
 49→
 50→    // Setup permission handler
 51→    this.permissionHandler = new PermissionHandler(
 52→      this.bot,
 53→      this.telegramConfig.chatId,
 54→      (sessionId) => (this.core as OpenACPCore).sessionManager.getSession(sessionId),
 55→      (notification) => this.sendNotification(notification),
 56→    )
 57→    this.permissionHandler.setupCallbackHandler()
 58→
 59→    // Setup commands
 60→    setupCommands(this.bot, this.core as OpenACPCore, this.telegramConfig.chatId)
 61→
 62→    // Setup message routing
 63→    this.setupRoutes()
 64→
 65→    // Start bot polling
 66→    this.bot.start({
 67→      allowed_updates: ['message', 'callback_query'],
 68→      onStart: () => log.info('Telegram bot started'),
 69→    })
 70→
 71→    // Spawn assistant (after bot is started so it can send messages)
 72→    try {
 73→      this.assistantSession = await spawnAssistant(
 74→        this.core as OpenACPCore,
 75→        this,
 76→        this.assistantTopicId,
 77→      )
 78→    } catch (err) {
 79→      log.error('Failed to spawn assistant:', err)
 80→    }
 81→  }
 82→
 83→  async stop(): Promise<void> {
 84→    if (this.assistantSession) {
 85→      await this.assistantSession.destroy()
 86→    }
 87→    await this.bot.stop()
 88→  }
 89→
 90→  private setupRoutes(): void {
 91→    this.bot.on('message:text', async (ctx) => {
 92→      const threadId = ctx.message.message_thread_id
 93→
 94→      // General topic or no thread → redirect to assistant
 95→      if (!threadId) {
 96→        const html = redirectToAssistant(this.telegramConfig.chatId, this.assistantTopicId)
 97→        await ctx.reply(html, { parse_mode: 'HTML' })
 98→        return
 99→      }
100→
101→      // Notification topic → ignore
102→      if (threadId === this.notificationTopicId) return
103→
104→      // Assistant topic → forward to assistant session
105→      if (threadId === this.assistantTopicId) {
106→        await handleAssistantMessage(this.assistantSession, ctx.message.text)
107→        return
108→      }
109→
110→      // Session topic → forward to core
111→      await (this.core as OpenACPCore).handleMessage({
112→        channelId: 'telegram',
113→        threadId: String(threadId),
114→        userId: String(ctx.from.id),
115→        text: ctx.message.text,
116→      })
117→    })
118→  }
119→
120→  // --- ChannelAdapter implementations ---
121→
122→  async sendMessage(sessionId: string, content: OutgoingMessage): Promise<void> {
123→    const session = (this.core as OpenACPCore).sessionManager.getSession(sessionId)
124→    if (!session) return
125→    const threadId = Number(session.threadId)
126→
127→    switch (content.type) {
128→      case 'thought': {
129→        // Skip thought/thinking content — it's internal agent reasoning
130→        // Users don't need to see it
131→        break
132→      }
133→
134→      case 'text': {
135→        let draft = this.sessionDrafts.get(sessionId)
136→        if (!draft) {
137→          draft = new MessageDraft(this.bot, this.telegramConfig.chatId, threadId)
138→          this.sessionDrafts.set(sessionId, draft)
139→        }
140→        draft.append(content.text)
141→        break
142→      }
143→
144→      case 'tool_call': {
145→        await this.finalizeDraft(sessionId)
146→        const msg = await this.bot.api.sendMessage(this.telegramConfig.chatId,
147→          formatToolCall(content.metadata as any),
148→          { message_thread_id: threadId, parse_mode: 'HTML', disable_notification: true }
149→        )
150→        if (!this.toolCallMessages.has(sessionId)) {
151→          this.toolCallMessages.set(sessionId, new Map())
152→        }
153→        this.toolCallMessages.get(sessionId)!.set(content.metadata?.id as string, msg.message_id)
154→        break
155→      }
156→
157→      case 'tool_update': {
158→        const msgId = this.toolCallMessages.get(sessionId)?.get(content.metadata?.id as string)
159→        if (msgId) {
160→          try {
161→            await this.bot.api.editMessageText(this.telegramConfig.chatId, msgId,
162→              formatToolUpdate(content.metadata as any),
163→              { parse_mode: 'HTML' }
164→            )
165→          } catch { /* edit failed */ }
166→        }
167→        break
168→      }
169→
170→      case 'plan': {
171→        await this.finalizeDraft(sessionId)
172→        await this.bot.api.sendMessage(this.telegramConfig.chatId,
173→          formatPlan(content.metadata as any),
174→          { message_thread_id: threadId, parse_mode: 'HTML', disable_notification: true }
175→        )
176→        break
177→      }
178→
179→      case 'usage': {
180→        // Show usage stats
181→        await this.bot.api.sendMessage(this.telegramConfig.chatId,
182→          formatUsage(content.metadata as any),
183→          { message_thread_id: threadId, parse_mode: 'HTML', disable_notification: true }
184→        )
185→        break
186→      }
187→
188→      case 'session_end': {
189→        await this.finalizeDraft(sessionId)
190→        this.sessionDrafts.delete(sessionId)
191→        this.toolCallMessages.delete(sessionId)
192→        await this.bot.api.sendMessage(this.telegramConfig.chatId,
193→          `✅ <b>Done</b>`,
194→          { message_thread_id: threadId, parse_mode: 'HTML', disable_notification: true }
195→        )
196→        break
197→      }
198→
199→      case 'error': {
200→        await this.finalizeDraft(sessionId)
201→        await this.bot.api.sendMessage(this.telegramConfig.chatId,
202→          `❌ <b>Error:</b> ${escapeHtml(content.text)}`,
203→          { message_thread_id: threadId, parse_mode: 'HTML', disable_notification: true }
204→        )
205→        break
206→      }
207→    }
208→  }
209→
210→  async sendPermissionRequest(sessionId: string, request: PermissionRequest): Promise<void> {
211→    const session = (this.core as OpenACPCore).sessionManager.getSession(sessionId)
212→    if (!session) return
213→    await this.permissionHandler.sendPermissionRequest(session, request)
214→  }
215→
216→  async sendNotification(notification: NotificationMessage): Promise<void> {
217→    if (!this.notificationTopicId) return
218→    const emoji: Record<string, string> = {
219→      completed: '✅', error: '❌', permission: '🔐', input_required: '💬',
220→    }
221→    let text = `${emoji[notification.type] || 'ℹ️'} <b>${escapeHtml(notification.sessionName || notification.sessionId)}</b>\n`
222→    text += escapeHtml(notification.summary)
223→    if (notification.deepLink) {
224→      text += `\n\n<a href="${notification.deepLink}">→ Go to message</a>`
225→    }
226→    await this.bot.api.sendMessage(this.telegramConfig.chatId, text, {
227→      message_thread_id: this.notificationTopicId,
228→      parse_mode: 'HTML',
229→      disable_notification: false,
230→    })
231→  }
232→
233→  async createSessionThread(sessionId: string, name: string): Promise<string> {
234→    return String(await createSessionTopic(this.bot, this.telegramConfig.chatId, name))
235→  }
236→
237→  async renameSessionThread(sessionId: string, newName: string): Promise<void> {
238→    const session = (this.core as OpenACPCore).sessionManager.getSession(sessionId)
239→    if (!session) return
240→    await renameSessionTopic(this.bot, this.telegramConfig.chatId, Number(session.threadId), newName)
241→  }
242→
243→  private async finalizeDraft(sessionId: string): Promise<void> {
244→    const draft = this.sessionDrafts.get(sessionId)
245→    if (draft) {
246→      await draft.finalize()
247→      this.sessionDrafts.delete(sessionId)
248→    }
249→  }
250→}
251→

  1→import { z } from 'zod'
  2→import * as fs from 'node:fs'
  3→import * as path from 'node:path'
  4→import * as os from 'node:os'
  5→import { log } from './log.js'
  6→
  7→const TelegramChannelSchema = z.object({
  8→  enabled: z.boolean().default(false),
  9→  botToken: z.string(),
 10→  chatId: z.number(),
 11→  notificationTopicId: z.number().nullable().default(null),
 12→  assistantTopicId: z.number().nullable().default(null),
 13→}).optional()
 14→
 15→const AgentSchema = z.object({
 16→  command: z.string(),
 17→  args: z.array(z.string()).default([]),
 18→  workingDirectory: z.string().optional(),
 19→  env: z.record(z.string(), z.string()).default({}),
 20→})
 21→
 22→export const ConfigSchema = z.object({
 23→  channels: z.object({
 24→    telegram: TelegramChannelSchema,
 25→  }),
 26→  agents: z.record(z.string(), AgentSchema),
 27→  defaultAgent: z.string(),
 28→  workspace: z.object({
 29→    baseDir: z.string().default('~/openacp-workspace'),
 30→  }).default({}),
 31→  security: z.object({
 32→    allowedUserIds: z.array(z.string()).default([]),
 33→    maxConcurrentSessions: z.number().default(5),
 34→    sessionTimeoutMinutes: z.number().default(60),
 35→  }).default({}),
 36→})
 37→
 38→export type Config = z.infer<typeof ConfigSchema>
 39→
 40→export function expandHome(p: string): string {
 41→  if (p.startsWith('~')) {
 42→    return path.join(os.homedir(), p.slice(1))
 43→  }
 44→  return p
 45→}
 46→
 47→const DEFAULT_CONFIG = {
 48→  channels: {
 49→    telegram: {
 50→      enabled: false,
 51→      botToken: "YOUR_BOT_TOKEN_HERE",
 52→      chatId: 0,
 53→      notificationTopicId: null,
 54→      assistantTopicId: null
 55→    }
 56→  },
 57→  agents: {
 58→    claude: { command: "claude-agent-acp", args: [], env: {} },
 59→    codex: { command: "codex", args: ["--acp"], env: {} }
 60→  },
 61→  defaultAgent: "claude",
 62→  workspace: { baseDir: "~/openacp-workspace" },
 63→  security: { allowedUserIds: [], maxConcurrentSessions: 5, sessionTimeoutMinutes: 60 }
 64→}
 65→
 66→export class ConfigManager {
 67→  private config!: Config
 68→  private configPath: string
 69→
 70→  constructor() {
 71→    this.configPath = process.env.OPENACP_CONFIG_PATH || expandHome('~/.openacp/config.json')
 72→  }
 73→
 74→  async load(): Promise<void> {
 75→    // 1. Ensure directory exists
 76→    const dir = path.dirname(this.configPath)
 77→    fs.mkdirSync(dir, { recursive: true })
 78→
 79→    // 2. If config file doesn't exist, create default
 80→    if (!fs.existsSync(this.configPath)) {
 81→      fs.writeFileSync(this.configPath, JSON.stringify(DEFAULT_CONFIG, null, 2))
 82→      log.info(`Config created at ${this.configPath}`)
 83→      log.info('Please edit it with your Telegram bot token and chat ID, then restart.')
 84→      process.exit(1)
 85→    }
 86→
 87→    // 3. Read and parse
 88→    const raw = JSON.parse(fs.readFileSync(this.configPath, 'utf-8'))
 89→
 90→    // 4. Apply env var overrides
 91→    this.applyEnvOverrides(raw)
 92→
 93→    // 5. Validate with Zod
 94→    const result = ConfigSchema.safeParse(raw)
 95→    if (!result.success) {
 96→      log.error('Config validation failed:')
 97→      for (const issue of result.error.issues) {
 98→        log.error(`  ${issue.path.join('.')}: ${issue.message}`)
 99→      }
100→      process.exit(1)
101→    }
102→    this.config = result.data
103→  }
104→
105→  get(): Config {
106→    return this.config
107→  }
108→
109→  async save(updates: Record<string, unknown>): Promise<void> {
110→    // Read current file, merge updates, write back
111→    const raw = JSON.parse(fs.readFileSync(this.configPath, 'utf-8'))
112→    this.deepMerge(raw, updates)
113→    fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2))
114→    // Re-validate and update in-memory config
115→    const result = ConfigSchema.safeParse(raw)
116→    if (result.success) {
117→      this.config = result.data
118→    }
119→  }
120→
121→  resolveWorkspace(input?: string): string {
122→    if (!input) {
123→      const resolved = expandHome(this.config.workspace.baseDir)
124→      fs.mkdirSync(resolved, { recursive: true })
125→      return resolved
126→    }
127→    if (input.startsWith('/') || input.startsWith('~')) {
128→      const resolved = expandHome(input)
129→      fs.mkdirSync(resolved, { recursive: true })
130→      return resolved
131→    }
132→    // Named workspace → lowercase, under baseDir
133→    const name = input.toLowerCase()
134→    const resolved = path.join(expandHome(this.config.workspace.baseDir), name)
135→    fs.mkdirSync(resolved, { recursive: true })
136→    return resolved
137→  }
138→
139→  private applyEnvOverrides(raw: Record<string, unknown>): void {
140→    const overrides: [string, string[]][] = [
141→      ['OPENACP_TELEGRAM_BOT_TOKEN', ['channels', 'telegram', 'botToken']],
142→      ['OPENACP_TELEGRAM_CHAT_ID', ['channels', 'telegram', 'chatId']],
143→      ['OPENACP_DEFAULT_AGENT', ['defaultAgent']],
144→    ]
145→    for (const [envVar, configPath] of overrides) {
146→      const value = process.env[envVar]
147→      if (value !== undefined) {
148→        let target = raw as Record<string, any>
149→        for (let i = 0; i < configPath.length - 1; i++) {
150→          if (!target[configPath[i]]) target[configPath[i]] = {}
151→          target = target[configPath[i]]
152→        }
153→        const key = configPath[configPath.length - 1]
154→        // Convert chatId to number
155→        target[key] = key === 'chatId' ? Number(value) : value
156→      }
157→    }
158→  }
159→
160→  private deepMerge(target: Record<string, any>, source: Record<string, any>): void {
161→    for (const key of Object.keys(source)) {
162→      if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
163→        if (!target[key]) target[key] = {}
164→        this.deepMerge(target[key], source[key])
165→      } else {
166→        target[key] = source[key]
167→      }
168→    }
169→  }
170→}
171→

 1→import type { AgentManager } from './agent-manager.js'
 2→import { Session } from './session.js'
 3→
 4→export class SessionManager {
 5→  private sessions: Map<string, Session> = new Map()
 6→
 7→  async createSession(
 8→    channelId: string,
 9→    agentName: string,
10→    workingDirectory: string,
11→    agentManager: AgentManager,
12→  ): Promise<Session> {
13→    const agentInstance = await agentManager.spawn(agentName, workingDirectory)
14→    const session = new Session({ channelId, agentName, workingDirectory, agentInstance })
15→    this.sessions.set(session.id, session)
16→    return session
17→  }
18→
19→  getSession(sessionId: string): Session | undefined {
20→    return this.sessions.get(sessionId)
21→  }
22→
23→  getSessionByThread(channelId: string, threadId: string): Session | undefined {
24→    for (const session of this.sessions.values()) {
25→      if (session.channelId === channelId && session.threadId === threadId) {
26→        return session
27→      }
28→    }
29→    return undefined
30→  }
31→
32→  async cancelSession(sessionId: string): Promise<void> {
33→    const session = this.sessions.get(sessionId)
34→    if (session) await session.cancel()
35→  }
36→
37→  listSessions(channelId?: string): Session[] {
38→    const all = Array.from(this.sessions.values())
39→    if (channelId) return all.filter(s => s.channelId === channelId)
40→    return all
41→  }
42→
43→  async destroyAll(): Promise<void> {
44→    for (const session of this.sessions.values()) {
45→      await session.destroy()
46→    }
47→    this.sessions.clear()
48→  }
49→}
