  1→import { nanoid } from 'nanoid'
  2→import type { AgentInstance } from './agent-instance.js'
  3→import type { ChannelAdapter } from './channel.js'
  4→import type { SessionStatus } from './types.js'
  5→import { log } from './log.js'
  6→
  7→export class Session {
  8→  id: string
  9→  channelId: string
 10→  threadId: string = ''
 11→  agentName: string
 12→  workingDirectory: string
 13→  agentInstance: AgentInstance
 14→  status: SessionStatus = 'initializing'
 15→  name?: string
 16→  promptQueue: string[] = []
 17→  promptRunning: boolean = false
 18→  createdAt: Date = new Date()
 19→  adapter?: ChannelAdapter  // Set by wireSessionEvents for renaming
 20→  pendingPermission?: { requestId: string; resolve: (optionId: string) => void }
 21→
 22→  constructor(opts: {
 23→    id?: string
 24→    channelId: string
 25→    agentName: string
 26→    workingDirectory: string
 27→    agentInstance: AgentInstance
 28→  }) {
 29→    this.id = opts.id || nanoid(12)
 30→    this.channelId = opts.channelId
 31→    this.agentName = opts.agentName
 32→    this.workingDirectory = opts.workingDirectory
 33→    this.agentInstance = opts.agentInstance
 34→  }
 35→
 36→  async enqueuePrompt(text: string): Promise<void> {
 37→    if (this.promptRunning) {
 38→      this.promptQueue.push(text)
 39→      log.debug(`Prompt queued for session ${this.id} (${this.promptQueue.length} in queue)`)
 40→      return
 41→    }
 42→    await this.runPrompt(text)
 43→  }
 44→
 45→  private async runPrompt(text: string): Promise<void> {
 46→    this.promptRunning = true
 47→    this.status = 'active'
 48→
 49→    try {
 50→      await this.agentInstance.prompt(text)
 51→
 52→      // Auto-name after first user prompt
 53→      if (!this.name) {
 54→        await this.autoName()
 55→      }
 56→    } catch (err) {
 57→      this.status = 'error'
 58→      log.error(`Prompt failed for session ${this.id}:`, err)
 59→    } finally {
 60→      this.promptRunning = false
 61→
 62→      // Process next queued prompt
 63→      if (this.promptQueue.length > 0) {
 64→        const next = this.promptQueue.shift()!
 65→        await this.runPrompt(next)
 66→      }
 67→    }
 68→  }
 69→
 70→  // NOTE: This injects a summary prompt into the agent's conversation history.
 71→  // Known Phase 1 limitation — the agent sees this prompt in its context.
 72→  private async autoName(): Promise<void> {
 73→    let title = ''
 74→    const prevHandler = this.agentInstance.onSessionUpdate
 75→    this.agentInstance.onSessionUpdate = (event) => {
 76→      if (event.type === 'text') title += event.content
 77→    }
 78→
 79→    try {
 80→      await this.agentInstance.prompt(
 81→        'Summarize this conversation in max 5 words for a topic title. Reply ONLY with the title, nothing else.'
 82→      )
 83→      this.name = title.trim().slice(0, 50)
 84→
 85→      // Rename the topic on the channel
 86→      if (this.adapter && this.name) {
 87→        await this.adapter.renameSessionThread(this.id, this.name)
 88→      }
 89→    } catch {
 90→      this.name = `Session ${this.id.slice(0, 6)}`
 91→    } finally {
 92→      this.agentInstance.onSessionUpdate = prevHandler
 93→    }
 94→  }
 95→
 96→  async cancel(): Promise<void> {
 97→    this.status = 'cancelled'
 98→    await this.agentInstance.cancel()
 99→  }
100→
101→  async destroy(): Promise<void> {
102→    await this.agentInstance.destroy()
103→  }
104→}
